SELECT problem_id, COUNT(*) AS steps FROM "PGcode_interactive_dry_runs"
WHERE problem_id IN (
  'balanced-binary-tree','binary-tree-right-side','construct-from-preorder-inorder','diameter-binary-tree',
  'kth-smallest-bst','lowest-common-ancestor','validate-bst',
  'connected-components','graph-valid-tree','redundant-connection','walls-and-gates','word-ladder',
